package com.google.gson;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.lang.reflect.Field;
import java.util.ArrayList;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class JsonArrayTest {

  private JsonArray jsonArray;

  @BeforeEach
  public void setUp() {
    jsonArray = new JsonArray();
  }

  @Test
  public void testSize_EmptyElements() throws Exception {
    // elements should be empty initially
    int size = jsonArray.size();
    assertEquals(0, size);
  }

  @Test
  public void testSize_WithElements() throws Exception {
    // Use reflection to access private 'elements' field and add mock elements
    Field elementsField = JsonArray.class.getDeclaredField("elements");
    elementsField.setAccessible(true);
    @SuppressWarnings("unchecked")
    ArrayList<JsonElement> elements = (ArrayList<JsonElement>) elementsField.get(jsonArray);

    elements.add(new JsonPrimitive("element1"));
    elements.add(new JsonPrimitive(123));
    elements.add(new JsonPrimitive(true));

    int size = jsonArray.size();
    assertEquals(3, size);
  }
}
